"""
mkt-context | 1 Kings 1-2
Run: python3 scripts/zc-context-1kings-1-2.py

Ch 1: Royal succession in Iron Age Israel; the ANE court; anointing at Gihon
Ch 2: Deathbed royal testament genre; blood-guilt law; Zadokite establishment

Key context:
- ANE succession politics — comparable to Hittite, Mesopotamian royal succession narratives
- Deuteronomic ideal of kingship (Deut 17) as the theological frame for Solomon's installation
- Eli's-house prophecy (1 Sam 2) fulfilled in Abiathar's expulsion
- Blood-guilt formulae in Israelite covenant law
"""

import json
import pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}


def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


KINGS1_CONTEXT_CH1_2 = {
    "1": {
        "1": "<p>1-2 Kings (originally one book, divided in the LXX) narrates the history of the united monarchy under Solomon and then the divided monarchy from Rehoboam/Jeroboam through the fall of Israel (722 BCE) and Judah (586 BCE). It is the crown document of the Deuteronomistic History (Deuteronomy–2 Kings), written and edited in the light of the Deuteronomic covenant — evaluating each king by the standard: 'did he do what was right in the eyes of YHWH, as David his father did?' The opening succession narrative (chs 1-2) belongs to the 'Succession Narrative' or 'Court History' of David (2 Sam 9-20 + 1 Kings 1-2), widely regarded as one of the earliest and most sophisticated prose narratives in world literature, marked by psychological realism and political nuance.</p>",
        "2": "<p>The medical prescription for David — a young virgin to warm the aging king — reflects a practice attested in ANE literature and later mentioned in the Hippocratic corpus: the therapeutic use of body warmth for the elderly. In the ancient world, the king's bodily vigor was linked to the fertility and prosperity of the land (the 'sacral kingship' concept in ANE royal ideology). David's physical decline is therefore politically and cosmologically significant, not merely personal. The Deuteronomistic narrator presents the succession crisis as arising naturally from David's incapacity rather than from explicit dynastic planning.</p>",
        "3": "<p>The search for a beautiful young woman 'throughout all the territory of Israel' is a royal prerogative attested in ANE texts — the Persian king Ahasuerus conducts a similar search in the book of Esther (2:2-4). The scope of the search (all Israel) demonstrates the functioning of royal administration across tribal territories, an infrastructure that Solomon will later expand and exploit (1 Kings 4's district system). Shunem, in the Jezreel Valley, is approximately 50 miles north of Jerusalem — the search reaches into the northern tribal territories, foreshadowing the pan-Israelite character of Solomon's kingdom.</p>",
        "4": "<p>The explicit notation that Abishag was David's attendant (<em>mĕšāreṯeṯ</em>) but 'the king did not know her' (<em>wĕhammelek lō yĕḏāʿāh</em>) is legally and narratively significant. In the ANE, the women of the royal household — wives, concubines, attendants — were symbols and instruments of royal authority. Possession of or access to a king's women was a succession claim (compare 2 Sam 16:21-22: Hushai's counsel to Absalom to take David's concubines publicly). The narrator's insistence on David's non-consummation of the relationship means Abishag's status is ambiguous enough to be politically weaponized in ch 2.</p>",
        "5": "<p>Adonijah's public display — chariot, horsemen, fifty runners before him — replicates Absalom's succession bid (2 Sam 15:1) almost verbatim. The chariot-and-horsemen display was the standard ANE iconography of royal power: in Egyptian and Mesopotamian palace art, the king appears in his chariot as the supreme symbol of sovereignty. Running footmen before the chariot (<em>rāṣîm</em>) are attested in both Israelite (1 Sam 8:11) and ANE contexts as the king's honor guard. Adonijah is performing the public ritual of kingship before he has any authorization for it.</p>",
        "6": "<p>The parental failure noted — David 'never disciplined him at any time' — is the Deuteronomic counterpart of the priestly warning about Eli's sons (1 Sam 3:13: he did not restrain his sons). The parallel is deliberate: the Samuel narratives and the Kings narratives both identify the failure to exercise parental-covenantal discipline as a structural problem in the families of Israel's leaders. The father who will not correct his son creates a son who believes he can self-constitute his own authority — which is the definition of the Deuteronomic's 'doing what is right in one's own eyes.'</p>",
        "7": "<p>The political alignment of Joab (military) and Abiathar (priestly) with Adonijah represents a coalition of the old establishment — figures whose power base was rooted in the previous generation. Joab has been David's military commander since Hebron but has repeatedly acted autonomously against David's wishes (killing Abner, Amasa, Absalom). Abiathar descends from Eli's priestly line and has served David since the Nob massacre. Their support for Adonijah is the establishment's preference for continuity and the maintenance of existing power networks over the prophetically designated new order.</p>",
        "8": "<p>The counter-coalition — Zadok, Nathan, Benaiah — represents the new institutional order that the Solomonic succession will consolidate. Zadok appears to be of the Eleazar/Phinehas line (distinct from Abiathar's Ithamar/Eli line), though his exact genealogy is disputed in scholarship. Nathan the prophet is David's court prophet since the 2 Sam 7 oracle and the 2 Sam 12 confrontation. Benaiah commands the Cherethites and Pelethites (professional mercenaries) who answer directly to the king rather than to the tribal levy. This triad represents priestly legitimacy, prophetic endorsement, and military professionalism — the three pillars of the new order.</p>",
        "9": "<p>En-rogel (the Fuller's Spring) is located at the junction of the Kidron and Hinnom valleys, just south of Jerusalem's walls — technically outside the city. Adonijah's choice of this location for his coronation feast is significant: it is near enough to Jerusalem to make a political statement but outside the city walls, perhaps suggesting some uncertainty about his position relative to the royal court. The sacrificial feast as political covenant-meal is well attested in the ANE — the participants are simultaneously sharing food and constituting a political coalition. The guest list (king's sons + royal servants + Judahite men) delineates the scope of the Adonijah faction.</p>",
        "10": "<p>The deliberate exclusion of Nathan, Benaiah, and the professional warriors (<em>gibbōrîm</em>) from Adonijah's coronation feast marks the limits of his coalition. In ANE political culture, the feast was the public ratification of factional allegiance; those excluded were by definition outside the coalition. Adonijah's exclusion of Solomon — his full brother by birth (both sons of David, both from the same mother? — actually no: Adonijah is son of Haggith; Solomon is son of Bathsheba) reveals the succession as a zero-sum competition. The excluded figures form the core of the successful counter-succession.</p>",
        "11": "<p>Nathan's approach to Bathsheba rather than directly to David reflects the political reality of the court: the queen-mother (<em>geḇîrâ</em>) had recognized institutional standing in Israelite and Judahite court culture. 1 Kings 15:13 (Asa removes Maacah from the <em>geḇîrâ</em> position) and 2 Kings 10:13 (the brothers of Ahaziah going to greet the sons of the queen mother) both confirm that the queen-mother held a real office, not merely a ceremonial title. Nathan's strategy uses the institutional leverage of the queen-mother to approach David through the most emotionally and politically effective channel.</p>",
        "12": "<p>Nathan's counsel is structured as political strategy, not merely personal advice. The two-witness approach — Bathsheba first, Nathan second — corresponds to the Deuteronomic requirement that a serious matter be established by two or three witnesses (Deut 19:15). Nathan is ensuring that the succession claim has the maximum legal weight: personal oath (invoked by Bathsheba), prophetic confirmation (provided by Nathan). The sequence creates a legal case, not just a personal appeal. This is the Deuteronomistic narrative's way of legitimizing Solomon's succession through proper institutional process rather than mere dynastic accident.</p>",
        "13": "<p>The oath invoked by Bathsheba — 'did you not swear to me by YHWH that Solomon your son shall reign after me?' — is not directly narrated earlier in the Samuel narrative. Scholars debate whether this reflects a lost tradition, a private promise unrecorded, or a narrative assumption of the reader's knowledge. The Deuteronomistic History frequently presupposes information that it does not directly narrate. What matters theologically is that the oath was sworn 'by YHWH' (<em>bĕYHWH</em>) — making its fulfillment a matter of covenant obligation, not merely political preference.</p>",
        "14": "<p>Nathan's promise to follow Bathsheba into the king's presence creates a narrative tension: two independent sources of information will converge on David, each confirming the other. In ANE court procedure, a report confirmed by two separate witnesses carries maximum credibility and demands response. Nathan is not merely providing personal support to Bathsheba but constituting a formal legal inquiry that requires royal decision. The word <em>ʾăḏaqqēr</em> (I will supplement/complete your words) in some manuscripts suggests Nathan has a specific role: to fill in what Bathsheba cannot or should not say directly.</p>",
        "15": "<p>The inner chamber (<em>ḥeḏer</em>) setting — David lying in the private room being tended by Abishag — frames the entire succession narrative around the contrast between private incapacity and public political crisis. The most powerful king Israel had known cannot keep warm in his own bed while outside his window a succession battle is being fought over who will inherit everything he built. The narrative's psychological realism is characteristic of the Court History: it does not idealize its subjects but presents them as complex human beings in complex circumstances.</p>",
        "16": "<p>Bathsheba's prostration and formal petition (<em>māh-lāḵ</em>, 'What is the matter with you?') follows the standard protocol for approaching a superior in the ANE world: entrance, prostration, formal request for permission to speak. The court protocol scenes in 1-2 Kings consistently show this formal procedure — even the queen mother must approach the king through the proper channels. This protocol both legitimizes the authority of the person being petitioned and establishes the seriousness of what is being requested.</p>",
        "17": "<p>The appeal to the covenant oath sworn 'by YHWH your God' (<em>ḇaYHWH ʾĕlōheykā</em>) elevates the succession matter from political preference to theological obligation. In the ANE world generally, and in the Deuteronomistic History specifically, oaths sworn by the deity were the most binding form of commitment — equivalent to treaty oaths between nations and covenant agreements between YHWH and Israel. Breaking such an oath was not merely political betrayal but covenant perjury. The narrative frames Solomon's succession as a theological necessity, not merely a political arrangement.</p>",
        "18": "<p>Bathsheba's rhetorical presentation of Adonijah's succession as already accomplished (<em>mālaḵ</em>, 'has become king,' in the perfect tense) gives the situation maximum urgency. The political reality is that Adonijah has performed the public rituals of succession without authorization — chariot display, coronation feast, royal proclamation. In the fluid political context of an incapacitated king, these public rituals carry real weight. The public expression 'Long live King Adonijah!' (v25) creates facts on the ground that David must either ratify or actively reverse. Bathsheba's framing makes clear that inaction is itself a decision — for Adonijah.</p>",
        "19": "<p>The guest list at Adonijah's feast — 'all the king's sons and Abiathar the priest and Joab the commander' — defines the scope of his coalition. The explicit inclusion of 'all the king's sons' (except Solomon) is the political context for Solomon's exclusion being so significant. Adonijah is constituting a pan-dynastic support base. But the list also reveals his limits: he has the old guard and the older siblings, but not the professional military (Benaiah), the institutional priesthood (Zadok), the prophetic voice (Nathan), or the queen mother's favor (Bathsheba).</p>",
        "20": "<p>The phrase 'the eyes of all Israel are upon you' (<em>ʿênê kol-yiśrāʾēl ʿāleykā</em>) is a political reality-claim: the succession decision belongs to the king, and the covenant community is waiting for his declaration. In the Deuteronomistic understanding of kingship, the king's authority is real but bounded — he is accountable to YHWH's covenant and to the covenant community. The nation's expectant attention is not merely flattery but the communal claim on David's duty to declare the succession clearly. Bathsheba is invoking this public accountability as political pressure.</p>",
        "21": "<p>Bathsheba's fear — that she and Solomon would be 'criminals' (<em>ḥaṭṭāʾîm</em>) after David dies — reflects the political reality of failed succession bids in the ANE. In Mesopotamian and Hittite succession law, unsuccessful claimants and their supporters faced execution or exile. The Hittite succession documents (Hittite Laws) and various Mesopotamian succession texts show that the victorious claimant regularly eliminated potential rivals and their networks. Bathsheba is not being melodramatic — she is accurately assessing the political stakes. Solomon's later elimination of Adonijah (ch 2:25) confirms the legitimacy of her fear.</p>",
        "22": "<p>Nathan's arrival precisely while Bathsheba is speaking creates the two-witness structure that ancient Near Eastern and Israelite legal tradition required for the establishment of significant matters (Deut 19:15). The narrative timing — whether historically exact or literarily constructed — serves the theological purpose of showing that the succession was established through proper procedural means, not merely through court intrigue. Nathan the prophet adds prophetic authority to the queen mother's personal appeal, constituting a case that David cannot easily dismiss or deflect.</p>",
        "23": "<p>The parallel prostration scenes — Bathsheba prostrating in v16 and Nathan prostrating in v23 — create a literary frame that establishes the formal character of the proceedings. Both approach through proper court protocol; both invoke the king's obligation; both represent different but complementary sources of authority (maternal/covenantal and prophetic/institutional). The narrative's formal symmetry signals its legal and theological seriousness: this is not a palace intrigue but a covenant matter being addressed through legitimate institutional channels.</p>",
        "24": "<p>Nathan's question — 'Did you say, Adonijah shall reign after me and he shall sit on my throne?' — is the rhetorical device that forces David to respond without Nathan having to make an accusation. In the ancient Near East, as in modern diplomacy, direct accusation of a superior was dangerous; the indirect question that invites self-correction is the safer and more politically effective form. Nathan is giving David the opportunity to take corrective action on his own authority rather than being compelled by prophetic denunciation. This respects the king's sovereignty while achieving the necessary outcome.</p>",
        "25": "<p>The feast at En-rogel — the third description of the same event (after vv9, 19) — is here presented through Nathan's voice to the king. The narrative repetition is not redundancy but dramatic device: the reader hears the event from three different angles (narrator, Bathsheba, Nathan), each adding new emotional and political force. Nathan's version emphasizes the formal proclamation 'Long live King Adonijah!' (<em>yĕḥî hammmelek ʾAḏōniyyāhû</em>) — exactly the formula that will be used for Solomon (v39) — making explicit that the acclamation formula has already been applied to the wrong king.</p>",
        "26": "<p>Nathan's self-inclusion among those not invited — 'your servant Nathan and Benaiah and the mighty men and your servant Solomon' — is politically astute. He is not merely making a personal complaint but articulating the scope of what has been excluded: the prophetic voice (Nathan), the military establishment (Benaiah and the gibbôrîm), and the designated heir (Solomon). The list constitutes the alternative coalition that, if mobilized, can reverse the succession. Nathan is implicitly offering David the means of correction while framing it as a matter of royal oversight.</p>",
        "27": "<p>Nathan's final question — 'Was this thing done by my lord the king?' — is the master rhetorical stroke. It offers David a face-saving option: if David says 'yes, I authorized Adonijah's succession,' then Nathan must accept it; if David says 'no, I did not authorize it,' then he must act to correct it. There is no third option; the question forces decision. The implication that David may have made this arrangement without informing his key advisors grants David the option to appear as a decisive king correcting an oversight rather than as a weak ruler whose sons are fighting over his throne.</p>",
        "28": "<p>David's immediate summons of Bathsheba signals the effectiveness of the strategy: the king has been moved to action. The narrative pacing here is rapid — question, summons, oath, commission — reflecting the urgency of the political situation. In ANE court narratives, swift royal decision following proper petition is a mark of the effective ruler. David's decisiveness in the face of the succession crisis rehabilitates him narratively: the king who was lying cold in his bed becomes, briefly, the decisive sovereign whose word initiates Solomon's legitimate succession.</p>",
        "29": "<p>The oath formula David invokes — 'as YHWH lives who has redeemed my soul from all adversity' — is a personal testimony before the formal succession declaration. By grounding the oath in YHWH's faithfulness to him personally throughout his life, David connects the succession promise to the entire arc of his covenant history with God. The verb <em>pāḏâ</em> (redeemed) is the marketplace-redemption term — paying a price to free someone. David has experienced YHWH's costly redemptive action throughout his life; he swears by the one who has done this for him.</p>",
        "30": "<p>The immediacy of David's declaration — 'so I will do this day' (<em>kî ḵēn ʾeʿĕśeh hayyôm hazzeh</em>) — is characteristic of the royal decree format in ANE documents. The king's word is effectual when spoken; the declaration creates the reality. The Deuteronomistic narrative consistently links royal word to royal action, especially in succession contexts. By declaring 'this day,' David not only promises but initiates — the subsequent verses describe the immediate execution of the anointing procession, confirming that the king's word was indeed effectual.</p>",
        "31": "<p>Bathsheba's acclamation '<em>yĕḥî ʾăḏōnî hammmelek Dāwîḏ lĕʿōlām</em>' (may my lord King David live forever!) is the standard court loyalty formula. The <em>lĕʿōlām</em> (forever) is a hyperbolic expression of loyalty — it does not claim literal immortality but expresses the absolute and unconditional character of the subject's devotion. Similar formulae appear in Mesopotamian and Egyptian court texts. In the narrative context, the formula is also bittersweet: David is clearly dying, and the acclamation of 'forever' is the court's last expression of loyalty to a king whose days are numbered.</p>",
        "32": "<p>The summoning of Zadok, Nathan, and Benaiah as the institutional triumvirate for Solomon's anointing establishes the three-institution model of legitimate Israelite authority: priestly (Zadok), prophetic (Nathan), and military (Benaiah). The Deuteronomistic History evaluates Israel's institutional life by how these three authorities function in relation to the Davidic covenant and the Mosaic Torah. Their coordinated participation in Solomon's succession establishes it as institutionally legitimate across all three domains — a level of institutional backing that Adonijah's faction, despite its political support, could not match.</p>",
        "33": "<p>The king's personal mule (<em>happirĕḏâ ʾăšer-lî</em>, 'the mule that is mine') as the vehicle for the succession procession reflects the ANE symbolic logic of succession: the new king rides on the old king's personal mount as public demonstration of legitimate inheritance. The mule (a hybrid of horse and donkey) was the preferred mount of the Israelite elite in this period — horses were associated with military/Philistine culture, donkeys with civilian/Israelite culture, and mules occupied the prestige middle ground. The royal mule's involvement makes the succession procession an explicitly royal act.</p>",
        "34": "<p>The anointing site at Gihon — the spring on the eastern slope of the City of David — was the primary water source for Jerusalem and a major public gathering point. The choice of a prominent, accessible location for the anointing (rather than a more private ceremony) ensures maximum public visibility. ANE royal anointing was fundamentally a public act — the smearing of sacred oil on the designated king was the visible symbol of divine authorization, witnessed by the covenant community. The subsequent blowing of the shofar and popular acclamation complete the public ratification of the succession.</p>",
        "35": "<p>The appointment formula 'he shall sit on my throne and reign in my place' (<em>ûhûʾ yimlōk taḥtāy</em>) is the co-regency declaration — Solomon is designated while David still lives. Co-regency was a common practice in the ANE when a king was incapacitated or wished to ensure smooth succession. Egyptian pharaohs regularly designated co-regents; Mesopotamian kings issued formal succession documents. In Israel, co-regency appears to have been less formal, but the narrative presents David's declaration as immediately effective: Solomon sits on the throne in v46 while David still lives (v1 uses 'drew near to die' rather than 'died').</p>",
        "36": "<p>Benaiah's response '<em>ʾāmēn kēn yōʾmar YHWH</em>' (Amen! May YHWH say so) is the military establishment's liturgical affirmation of the succession. The term <em>ʾāmēn</em> — from the root <em>ʾmn</em> (firm, faithful, sure) — serves here as an affirmation that YHWH's faithfulness will undergird what has been declared. It is one of the earliest liturgical uses of the term in the Hebrew Bible (cf. Num 5:22; Deut 27:15-26 for earlier liturgical uses). The combination of <em>ʾāmēn</em> with the petition 'May YHWH say so' is a prayer that the human declaration aligns with divine will.</p>",
        "37": "<p>Benaiah's blessing — 'As YHWH was with my lord the king, so may he be with Solomon' — invokes the YHWH-presence formula that runs through the entire Deuteronomistic History. Joshua 1:5 is its programmatic statement: 'as I was with Moses, so I will be with you.' The divine presence is the continuity that transcends individual kings — YHWH's accompaniment of the covenant community's leader is what makes leadership effective, not merely political skill or military prowess. Benaiah is praying that Solomon will inherit not just David's throne but David's relationship with YHWH.</p>",
        "38": "<p>The Cherethites and Pelethites — David's elite mercenary bodyguard of Philistine/Aegean origin — played a crucial role in David's reign as a force loyal personally to the king rather than to any tribal or factional interest. Their consistent identification with key royal moments (the Ark procession: 2 Sam 6:1; the Absalom crisis: 2 Sam 15:18; Sheba's revolt: 2 Sam 20:7) demonstrates their function as the royal professional guard that transcended Israelite tribal politics. Their participation in Solomon's anointing procession signals the professional military's transfer of loyalty to the new king.</p>",
        "39": "<p>The anointing oil from the sacred tent connects Solomon's anointing to the Mosaic institution of the tabernacle and the priestly system. Exodus 30:23-33 specifies the composition of the holy anointing oil and its exclusive sacred use — it was the same oil used to consecrate the tabernacle, its furniture, and Aaron's priestly vestments. The use of this specifically sacred oil (rather than ordinary oil) for the royal anointing establishes a theological connection between the Davidic kingship and the Mosaic covenant-institution. The king's anointing is not a secular political act but a sacred covenant-act parallel to priestly consecration.</p>",
        "40": "<p>The public celebration — playing flutes, rejoicing with great joy, the earth trembling from the sound (<em>waṯibbāqaʿ hāʾāreṣ bĕqôlām</em>) — is the covenant community's affirmation of the succession. In ANE royal ideology, the popular response to the new king's acclamation was read as divine endorsement: the people's voice was, in a sense, the deity's voice. The specific phrase 'the earth was split by the sound' is hyperbolic celebration language — exaggerated to convey the overwhelming popular enthusiasm that YHWH's choice was being ratified by Israel's enthusiastic response.</p>",
        "41": "<p>The sound of the celebration reaching Adonijah's feast at En-rogel creates a dramatic contrast: inside the feast, premature celebration; outside, the city's overwhelming endorsement of a different king. The narrative's dramatic irony — Adonijah is celebrating while being displaced — is one of its key devices. The city's trembling (<em>waṯibbāqaʿ hāʾāreṣ</em>) heard at En-rogel emphasizes both the distance (En-rogel is outside the city walls) and the overwhelming scale of Solomon's acclamation. The 'uproar of the city' (<em>qôl hāʿîr hōmiyyâ</em>) is the public voice of history turning against Adonijah.</p>",
        "42": "<p>The arrival of Jonathan son of Abiathar at Adonijah's feast to deliver the news is a deliberate narrative irony: it is the son of Adonijah's priestly supporter who brings the news of the coup's failure. The Abiathar family will be expelled from priestly service in the next chapter; the appearance of Jonathan here as messenger may subtly foreshadow the family's transition from insider political actor to peripheral figure. Adonijah's confident greeting ('you are a good man and bring good news') uses the root <em>bśr</em> (bearer of good news) that becomes the NT's <em>euangelion</em>; the irony is that the news is catastrophic for him.</p>",
        "43": "<p>Jonathan's report is a detailed recapitulation of the anointing procession — naming each institutional actor and the specific actions taken. This detailed report serves two narrative functions: it provides information to Adonijah (and to any reader who might need reminder of the events), and it demonstrates that the succession was executed exactly as David commanded (vv32-35), with every institutional legitimator in place. The report format itself — a messenger's precise recitation — is characteristic of ANE court communication, designed to convey complete and accurate information from court to outlying locations.</p>",
        "44": "<p>The listing of the institutional legitimators — 'the king sent with him Zadok the priest and Nathan the prophet and Benaiah son of Jehoiada' — in the messenger's report matches exactly the list of those not invited to Adonijah's feast (v8) and the list David commissioned (vv32-35). The correspondence is precise: those who were excluded from Adonijah's coalition are exactly those who legitimized Solomon's succession. The narrative's structural symmetry underscores the theological point: the excluded ones are the covenant-faithful ones whose participation constitutes legitimate succession.</p>",
        "45": "<p>Gihon as the anointing site has additional significance: it is one of the four rivers of Eden in Gen 2:13 — 'the name of the second river is Gihon; it is the one that flowed around the whole land of Cush.' Whether the identification is precise or symbolic, the use of the Eden-river name for Jerusalem's spring may carry cosmological resonance in the royal theology: Jerusalem as the center of the world, the place from which the blessing of divine governance flows. The later significance of Gihon in Hezekiah's water tunnel project (2 Chr 32:30) shows its ongoing strategic and symbolic importance in the Jerusalem narrative.</p>",
        "46": "<p>The statement that 'Solomon sits on the royal throne' (<em>gam yāšaḇ šĕlōmōh ʿal kissēʾ hammamlāḵâ</em>) — spoken by the messenger while David is still alive — confirms the co-regency arrangement. Solomon is enthroned as co-regent; the kingdom has effectively passed before David's death. This type of ante-mortem succession was common in the ANE when a king's health made it necessary. The messenger's report signals to Adonijah that the political situation is not merely disputed but definitively settled: Solomon is already seated on the throne with full institutional backing.</p>",
        "47": "<p>David's response — bowing in worship on his bed (<em>wayyišṯaḥû hammmelek ʿal-hammiššāh</em>) — is the pious king's proper response to covenant fulfillment. The blessing formula <em>bārûḵ YHWH ʾĕlōhê yiśrāʾēl</em> (blessed be YHWH God of Israel) is the standard liturgical doxology of the Psalter and the covenant community's proper response to divine faithfulness. In his final recorded act of worship, David is not a political operator but a covenant-keeper thanking YHWH for fulfilling his promise. The physical diminishment (bowing while lying in bed) makes the act more moving, not less.</p>",
        "48": "<p>'YHWH God of Israel who has given one to sit on my throne today while my own eyes see it' — David's testimony is the old man's greatest blessing: he has lived to see the covenant promise fulfilled. In the ancient world, dying without seeing one's legacy established was one of the deepest fears; dying with eyes that have witnessed the fulfillment of divine promise was the greatest blessing. The phrase 'while my eyes see' (<em>wĕʿênay rōʾôṯ</em>) is a personal testimony of witnessed fulfillment — the subjective experience of a man who has waited through exile, battles, failures, and restoration to see this moment.</p>",
        "49": "<p>The dissolution of Adonijah's faction — 'each went his own way' (<em>wayyēlĕḵû ʾîš lĕḏarKô</em>) — is the standard ancient Near Eastern formula for the dispersal of a defeated coalition. The sudden collapse of what appeared to be a strong political movement demonstrates the fragility of support built on anticipated victory rather than principled loyalty. The guest list at Adonijah's feast included all the king's sons and the elite of Jerusalem; within hours, they have all abandoned him. ANE political fidelity was conditional on perceived power — the moment the balance shifted, the coalition dissolved.</p>",
        "50": "<p>Adonijah's flight to the altar sanctuary at the sacred tent reflects the ancient Israelite institution of altar asylum: the altar was a place where even the guilty could appeal for clemency. Exodus 21:13 designates a 'place' to which the accidental manslayer may flee; the altar was the primary such place in pre-temple Israelite religion. Adonijah is not claiming innocence but appealing to the institution's mercy clause — the same provision he implicitly recognized when he grasped the altar horns. His fear of Solomon indicates he knows his succession attempt was illegitimate and its failure may be capital.</p>",
        "51": "<p>The report to Solomon that Adonijah 'fears King Solomon' (<em>yārēʾ ʾeṯ-hammmelek šĕlōmōh</em>) is diplomatically significant: it presents the situation as Adonijah seeking protection rather than continuing to claim the throne. In ANE court practice, the willingness to acknowledge a superior's authority was the precondition for clemency. Adonijah's request — that Solomon swear not to kill him — is the classic submission petition of the defeated pretender, paralleled in Mesopotamian and Egyptian succession narratives. Solomon's conditional mercy ('if he shows himself worthy') is the standard ANE formula for conditional clemency.</p>",
        "52": "<p>Solomon's condition — <em>ben-ḥayil</em> (man of valor/worth) = loyalty and competence — is the standard Israelite leadership term for reliable service. The conditional mercy formula ('not one of his hairs will fall') with its counterpart ('but if wickedness is found in him, he will die') mirrors the covenant structure of blessing and curse (Deut 27-28). Solomon is not merely being merciful but setting the terms of a covenant relationship: continued life is conditioned on continued loyalty. This conditional mercy is the most politically sophisticated response possible — it neither eliminates a potential future threat nor gives unconditional absolution that could be exploited.</p>",
        "53": "<p>The scene closes with Adonijah prostrating himself before Solomon — the formal act of submission of the defeated claimant to the victorious king — and Solomon's dismissal 'go to your house' (<em>lēḵ lĕḇêṯeḵā</em>). The house-arrest formula is the ANE equivalent of a supervised parole: the defeated pretender lives, but under surveillance, removed from the public sphere. The narrative has achieved its goal: the succession is established, the rival is neutralized, and Solomon rules with David still living as confirmation. The political crisis of ch 1 is resolved through legitimate institutional process, not raw power.</p>"
    },
    "2": {
        "1": "<p>David's deathbed charge to Solomon belongs to the ancient Near Eastern genre of the royal testament — the dying king's final instructions to his successor. Egyptian royal didactic texts (the 'Instructions of Amenemhat I' and the 'Instructions of Merikare') represent the best-known ANE examples of this genre: a king giving wisdom and political counsel to his heir. Within the Hebrew Bible, the genre appears in Moses's farewell (Deut 31-33), Jacob's blessings (Gen 49), and Joshua's farewell (Josh 23-24). David's charge is organized around the same structure: general theological principle (vv2-4) followed by specific political instructions (vv5-9).</p>",
        "2": "<p>'Be strong and show yourself a man' (<em>ḥāzaq wihyēh lĕʾîš</em>) is a formulaic commissioning charge that appears throughout the Deuteronomistic History: YHWH to Joshua (Josh 1:6, 7, 9: <em>ḥāzaq weʾĕmāṣ</em>); David to Solomon in 1 Chr 28:20. The formula combines two registers: physical courage (<em>ḥāzaq</em>) and moral integrity (<em>ʾîš</em>, manhood in the full sense of responsible covenant-keeping). The combination is the Deuteronomic ideal: effective leadership requires both the courage to act and the moral formation to act rightly. The formula is inherited from the warrior tradition but transformed by the Deuteronomic emphasis on Torah-fidelity.</p>",
        "3": "<p>The Deuteronomic charge — keep YHWH's statutes, commandments, ordinances, testimonies, walk in his ways — is the theological center of David's testament and the hermeneutical key to the entire Solomon narrative. 1 Kings 3-11 will show Solomon at his best (wisdom, temple, prayer) and then at his worst (foreign wives, high places, divided heart). The evaluative standard for this entire narrative arc is established here: the king who keeps Torah will prosper; the king who does not will see his kingdom divided. David's charge is the Deuteronomic verdict on the Solomonic narrative before it has begun.</p>",
        "4": "<p>The conditional form of the Davidic covenant — 'if your sons keep their way … you shall not lack a man on the throne of Israel' — reveals the tension within the covenant's structure. The Davidic covenant in 2 Sam 7 appears unconditional: 'I will not take my steadfast love from him, as I took it from Saul' (2 Sam 7:15). Here, David himself introduces conditionality: the dynasty's specific kings must walk in Torah faithfulness for the covenant's blessings to be realized. The Deuteronomistic editors of Kings hold both dimensions in tension: the dynasty persists (unconditional) but specific kings are judged and may be removed (conditional).</p>",
        "5": "<p>The definition of Joab's crime — 'he shed blood of war in peacetime, and put the blood of war on the belt of his robe and on the sandals of his feet' — is a precise legal formulation. In Israelite covenant law (and ANE law generally), killing in battle (<em>dam milḥāmâ</em>) was legally distinct from murder in peacetime. Joab killed Abner during what appeared to be a peace negotiation (2 Sam 3:27) and Amasa when greeting him as a friend (2 Sam 20:10). Both were technically murders despite the military context. The belt-and-sandal imagery of blood-guilt means Joab carries the stain of unjust killing in everything he does — his very clothing is marked by it.</p>",
        "6": "<p>David's appeal to Solomon's wisdom — 'act according to your wisdom' — anticipates the primary theme of the subsequent Solomon narrative: wisdom as the king's defining gift and calling. 1 Kings 3:5-14 narrates Solomon's request for and receipt of wisdom; 1 Kings 4:29-34 catalogs the scope of his wisdom; 1 Kings 10:1-13 shows the Queen of Sheba testing it. David's instruction regarding Joab deliberately delegates the means to Solomon's judgment rather than prescribing a specific course — which is itself a mark of wisdom: knowing when to prescribe exactly and when to trust the discernment of one's successor.</p>",
        "7": "<p>The instruction to show covenant loyalty (<em>ḥeseḏ</em>) to Barzillai's sons is the counterpart of the instructions about Joab and Shimei: where justice demands reckoning for the guilty, covenant loyalty requires care for those who showed faithfulness. Barzillai of Gilead provisioned David during Absalom's rebellion (2 Sam 17:27-29), demonstrating exactly the kind of covenant loyalty in adversity that the Deuteronomistic History values. The instruction to have them 'eat at your table' (<em>ʾōḵĕlê šulḥānĕkā</em>) is the covenant-inclusion formula — the same used for Mephibosheth (2 Sam 9:7): belonging to the covenant community is expressed through shared table fellowship.</p>",
        "8": "<p>Shimei's case is more complex than Joab's: David had sworn not to kill Shimei on his return from Absalom's rebellion (2 Sam 19:23: 'you shall not die'), but the oath was David's personal oath. David frames the Shimei matter for Solomon carefully: 'you know in your wisdom what you ought to do to him' — transferring judgment to Solomon while pointing to the prior crime and its ongoing blood-guilt. The geography noted — Shimei cursed David 'on the day I went to Mahanaim' — provides the precise historical context. Solomon's subsequent house-arrest arrangement (vv36-38) shows the exercise of the wisdom David commended.</p>",
        "9": "<p>The blood-guilt formula 'his blood will be on his own head' (<em>dāmô ʿal-rōʾšô</em>) is the Israelite covenant-law principle that self-incurred guilt carries its own penalty. Shimei's curse of YHWH's anointed was a capital offense under Exod 22:28 ('you shall not curse God, nor curse a ruler of your people'). David had suspended the execution of this sentence by his personal oath; but the guilt itself was not erased by the oath — it was merely suspended. Solomon's house-arrest arrangement with the boundary condition (vv36-38) is a sophisticated legal maneuver: it creates a new covenant with Shimei whose violation provides fresh legal grounds for execution without David's oath being violated.</p>",
        "10": "<p>'David slept with his fathers and was buried in the City of David' (<em>ʿîr Dāwîḏ</em>). The royal burial in Jerusalem — on the original Jebusite hill that David captured (2 Sam 5:7-9) and renamed the City of David — established the royal necropolis that would receive subsequent Davidic kings. Acts 2:29 (Peter's Pentecost sermon) notes that David's tomb was known to the audience 'to this day.' Archaeological investigation has not definitively located the Davidic tomb, but the tradition of royal burials on the eastern hill of Jerusalem is consistent with the narrative. The burial formula 'slept with his fathers' will be repeated for every subsequent king of Judah and Israel who dies in his own bed.</p>",
        "11": "<p>The summary of David's reign — 40 years total (7 in Hebron + 33 in Jerusalem) — is the Deuteronomistic historian's first use of the regnal summary formula that will structure the entire presentation of the monarchy in 1-2 Kings: king's name, accession age, reign length, mother's name, theological evaluation, and death/burial. The 40-year total corresponds to a standard generation-length in ancient reckoning and appears as the reign-length for both Saul and Solomon as well. The specific breakdown (7 in Hebron, 33 in Jerusalem) is supported by 2 Sam 2:11 and 5:4-5.</p>",
        "12": "<p>'The kingdom was firmly established in Solomon's hand' (<em>mamlaḵâ nāḵônâ bĕyaḏ šĕlōmōh</em>). The verb <em>kûn</em> (to be established, firm) is the Davidic covenant's signature word: 2 Sam 7:12, 16 uses the same root to describe YHWH's establishment of the Davidic throne forever. Its application to Solomon's consolidated kingdom in v12 and again in v46 frames the entire consolidation narrative as covenant fulfillment. The 'hand' (<em>yāḏ</em>) is the standard metonym for personal authority and ownership — the kingdom is 'in Solomon's hand' = under his effective control.</p>",
        "13": "<p>Adonijah's approach to Bathsheba after his failed coup is a political miscalculation of stunning proportions — or possibly a deliberate provocation. The queen mother had standing to intercede with Solomon (as demonstrated in v19), so the strategy was not inherently foolish. But the specific request — Abishag — was loaded with succession symbolism that Solomon would inevitably read as continued pretension. Whether Adonijah was genuinely naive about the implications or deliberately testing the limits of Solomon's clemency, the effect was the same: the execution of the conditional pardon that Solomon had given him in 1:52.</p>",
        "14": "<p>Adonijah's opening — 'I have something to say to you' followed by Bathsheba's 'speak' — follows standard ANE petition protocol. The brevity and formality of the exchange creates narrative tension: the reader knows from the first chapter that Adonijah is politically dangerous, and his approach to the queen mother after his failed coup is immediately suspicious. The narrative pacing here is deliberately slow — the formal request for permission to speak, the acceptance, the 'one thing I ask of you, do not refuse me' — building to the explosive request.</p>",
        "15": "<p>Adonijah's claim that 'all Israel set their faces on me to reign' invokes popular support rather than divine authorization as the ground for succession. This is the fundamental category error: in the Deuteronomistic understanding, legitimate kingship derives from divine election (expressed through prophetic designation and sacred anointing), not popular acclamation alone. The contrast between Adonijah's populism and Solomon's divinely sanctioned succession is the theological point of the entire narrative. The man who claims popular support as the ground for his legitimacy is precisely the man who lacks the only legitimate ground: YHWH's authorization.</p>",
        "16": "<p>The formal petition structure — 'I ask one thing of you, do not refuse me' — creates the narrative trap for Bathsheba. Her acceptance of the petition before knowing its content reflects either political naivety (she doesn't anticipate the content) or calculated risk (she is willing to bear the request to Solomon and let him decide). Solomon's reaction in v22 — 'why do you ask for Abishag for Adonijah? Ask the kingdom for him also!' — suggests that Bathsheba may not have understood the political implications of the request, though this is debated in scholarship. The narrative leaves her motivation ambiguous.</p>",
        "17": "<p>The request for Abishag as wife was politically explosive because of the ANE law of the royal harem: the women of the previous king passed to the successor, and unauthorized access to the royal harem was equivalent to a succession claim. The explicit examples in the narrative are instructive: Abner sleeping with Saul's concubine Rizpah (2 Sam 3:7 — Ish-bosheth's accusation against Abner implies the harem-claim logic); Absalom taking David's concubines publicly at Hushai's advice (2 Sam 16:21-22 — 'that all Israel may hear that you have become odious to your father'). Adonijah's request was read by Solomon as exactly what it was: a renewed succession claim, however thinly disguised.</p>",
        "18": "<p>Bathsheba's agreement to present the request — 'very well, I will speak for you to the king' — raises the interpretive question of her understanding of the political implications. The Deuteronomistic narrator does not provide her internal state. Commentators are divided: some read her as politically astute and deliberately allowing Adonijah to self-destruct; others read her as genuinely naive about the harem-succession logic. The narrative's theological point is clear regardless of Bathsheba's intent: Adonijah's own action is the instrument of his execution, not Solomon's arbitrary revenge.</p>",
        "19": "<p>Solomon rising to meet his mother, bowing to her, and placing a throne for her at his right hand demonstrates the institutional reality of the queen-mother's position in the Judahite court. The right hand of the king is the position of honor and authority (Ps 110:1: 'sit at my right hand'). The queen mother at the king's right hand is attested in the ancient Near East as a recognized court position — the <em>geḇîrâ</em> (great lady) had real standing. The dramatic irony of the scene: Bathsheba is received with maximum honor and is about to make a request whose content will lead to her son's brother's execution.</p>",
        "20": "<p>Solomon's promise — 'ask, my mother, for I will not refuse you' (<em>šăʾălî ʾimmi wĕlōʾ ʾāšîḇ ʾeṯ-p̄ānāyiḵ</em>) — before hearing the request is the narrative's literary trap. The unconditional promise given before the content is known is a storytelling motif that appears in several ancient narratives (Herod's promise to Herodias's daughter: Mark 6:22-25; Jephthah's vow: Judg 11:30-31). In each case, the unconditional promise creates a moral dilemma when the content is revealed. Solomon's promise here does not bind him to the request's content — his subsequent reaction shows he has no intention of honoring a request that constitutes a succession claim — but it establishes the irony of the scene.</p>",
        "21": "<p>Bathsheba's presentation of the request — 'let Abishag the Shunammite be given to Adonijah your brother as wife' — uses the fraternal designation ('your brother') in an attempt to soften the political implications. But the designation backfires: it is precisely because Adonijah is Solomon's brother — David's son — that a request for a figure from the royal household carries succession implications. Solomon's explosive response ('ask the kingdom for him as well!') demonstrates his political acuity: he sees the implications immediately and refuses to pretend the request is innocent.</p>",
        "22": "<p>Solomon's rhetorical escalation — 'why do you ask Abishag for Adonijah? Ask the kingdom for him and for Abiathar and for Joab!' — is the king's public declaration of the political meaning of the request. By naming Abiathar and Joab as part of the same coalition (which is historically accurate — they supported Adonijah in ch 1), Solomon is saying: the request for Abishag is not a private matter but the continuation of a factional claim on the throne. The naming of the entire Adonijah coalition explicitly shows that Solomon has been watching carefully and understands the political landscape completely.</p>",
        "23": "<p>Solomon's oath — 'God do so to me and more also if Adonijah has not spoken this word against his own life!' — is the self-imprecation formula that invokes divine judgment on the oath-taker if the statement is false. The formula <em>kōh yaʿăśeh-lî ʾĕlōhîm wĕḵōh yōsîp̄</em> appears throughout Samuel-Kings at moments of high-stakes commitment (Ruth 1:17; 1 Sam 3:17; 14:44; 2 Sam 19:13). The key phrase is 'against his own life' (<em>bĕnap̄šô dibbēr haddāḇār hazzeh</em>): Solomon is declaring that Adonijah's own request constitutes the evidence against himself — the request itself is the crime, making Adonijah the author of his own death sentence.</p>",
        "24": "<p>Solomon's grounding of his authority in YHWH's establishment of his throne — 'YHWH who has established me and placed me on the throne of David my father and who has made me a house as he promised' — is the theological justification for the execution. This is not arbitrary revenge but the protection of a YHWH-established order. The Davidic covenant (2 Sam 7) is the theological basis: YHWH has established this specific king and this specific dynasty, and any challenge to it is not merely political rebellion but theological provocation. Solomon understands his action as covenant-enforcement, not personal vengeance.</p>",
        "25": "<p>Benaiah son of Jehoiada serves as Solomon's executor throughout ch 2 — killing Adonijah (v25), Joab (v34), and Shimei (v46). His role as executor is consistent with his position as commander of the professional mercenary guard (Cherethites and Pelethites), which served as the royal police force as well as the military guard. Benaiah's loyalty to Solomon from the beginning (1:8) and his specific military role make him the appropriate instrument of royal justice. Each execution is reported with the same brief formula: <em>wayyippĕgaʿ-bô wayyāmōṯ</em> (he struck him and he died) — the administrative register of justice, without elaboration or lament.</p>",
        "26": "<p>Solomon's clemency toward Abiathar — banishment rather than execution — is grounded in three factors: his service as Ark-bearer, his solidarity with David in suffering, and the need to fulfill a specific divine prophecy (1 Sam 2:31-33). The prophecy against Eli's house was that none of his line would live to old age in the priestly service of the sanctuary. Abiathar's banishment to Anathoth (5 miles north of Jerusalem) fulfills the prophecy without Solomon having to execute a priest who served David faithfully. The legal phrase 'man of death' (<em>ʾîš māweṯ</em>, deserving of death) acknowledges the treason while explaining the commutation.</p>",
        "27": "<p>The fulfillment formula — 'to fulfill the word of YHWH that he spoke against the house of Eli in Shiloh' (<em>lĕmallēʾ ʾeṯ-dĕḇar YHWH ʾăšer dibbēr ʿal-bêṯ ʿēlî bĕšîlōh</em>) — is one of the most explicit examples of the Deuteronomistic narrator's theological interpretation of events as prophetic fulfillment. The prophecy of 1 Sam 2:27-36 (the man of God to Eli) and 1 Sam 3:11-14 (YHWH's word to Samuel) specified the end of Eli's priestly line. Its fulfillment here — five generations and approximately 130 years after the prophecy — demonstrates the Deuteronomistic History's core theological conviction: YHWH's word, once spoken, will be fulfilled in history, regardless of the time elapsed.</p>",
        "28": "<p>Joab's flight to the sacred tent when he hears of Adonijah's and Abiathar's fates demonstrates his political acuity: he understands that the consolidation is systematically eliminating his faction, and that the altar is his only remaining protection. The narrative detail that Joab 'had turned after Adonijah but had not turned after Absalom' is a calibrated political resume: Joab was not always a faction-player (he actively prevented Absalom's return and ultimately killed him against David's orders), but in the Adonijah matter he made a specific choice that now forfeits his standing with the new king.</p>",
        "29": "<p>Solomon's command to execute Joab at the altar — 'fall upon him' (<em>p̄ĕgaʿ-bô</em>) even in the sacred space — reflects the Exodus 21:14 exception to altar asylum: 'if a man willfully attacks another to kill him treacherously, you shall take him even from my altar, that he may die.' Joab's murders of Abner and Amasa were precisely treacherous, premeditated killings during apparent friendship/negotiation contexts. The altar asylum institution in Israelite law was designed for the accidental manslayer, not the deliberate murderer. Solomon's command is legally correct; Benaiah's initial hesitation (v29b: he reports back rather than acting) suggests the gravity of the act.</p>",
        "30": "<p>Joab's refusal to leave the altar — 'No, for here I will die' (<em>lōʾ kî p̄ōh ʾāmûṯ</em>) — is the final act of defiance of a man who has spent his career acting on his own military judgment against David's explicit wishes. He killed Abner (against David's covenant), Amasa (against David's appointment), and Absalom (against David's command). Now, facing the consequences of his final political miscalculation, he refuses to submit even to the altar's conditional protection. His declaration that he will die where he stands has a certain grim integrity: at least this refusal is honest self-assessment rather than another autonomous military decision.</p>",
        "31": "<p>Solomon's authorization for execution at the altar is grounded explicitly in the Mosaic law — 'as he said, strike him and bury him' — where the burial command acknowledges minimal respect even for the justly executed. The Exodus 21:14 exception (premeditated murderer at the altar) is the legal basis; Solomon is not overriding the altar sanctuary institution but applying its own exception clause. The Deuteronomistic narrator presents Solomon's action as legally correct and theologically necessary: Joab's unpunished blood-guilt would stain the reign if not addressed. The blood of Abner and Amasa 'returns upon Joab's head' — not arbitrary vengeance but covenant justice.</p>",
        "32": "<p>The theological interpretation of Joab's execution — 'YHWH will return his blood on his own head' — applies the divine-justice formula to a specific historical act. This formula (<em>wĕhēšîḇ YHWH ʾeṯ-dāmô ʿal-rōʾšô</em>) appears in contexts where blood-guilt is definitively resolved: the blood that was shed unjustly now returns to the one who shed it. The covenant-law principle is that unjust blood crying from the ground (Gen 4:10) creates an ongoing obligation of justice; Solomon's execution of Joab resolves the accumulated blood-guilt of his career. The theological framing makes the execution not a political murder but a covenantal necessity.</p>",
        "33": "<p>The contrast between blood-guilt passing to Joab's descendants and peace flowing to David's dynasty (<em>lĕḏāwîḏ ûlĕzarʿô ûlĕḇêṯô ûlĕkissĕʾô šālôm ʿaḏ-ʿôlām</em>) is the Deuteronomistic binary of covenant curse and blessing applied to specific people. The eternal peace (<em>šālôm ʿaḏ-ʿôlām</em>) promised to David's dynasty is the same Davidic covenant language of 2 Sam 7:16 — 'your house and your kingdom shall be made sure before me forever.' Solomon's consolidation is not merely political stabilization but covenant-fulfillment: the removal of sources of corruption and blood-guilt that would defile the dynasty.</p>",
        "34": "<p>Joab's burial 'in his own house in the wilderness' (<em>bĕḇêṯô bammiḏbār</em>) is a detail that suggests property in the Judean wilderness — consistent with his role as a wilderness fighter and general. The burial notation is significant: even the justly executed are buried (unlike some ANE execution practices that included exposure of the corpse). Israelite burial law required even executed criminals to be buried before nightfall (Deut 21:23). Joab's wilderness burial is not disgraceful but it is private — no royal funeral, no public mourning, no honor. The quietly literal end of the most powerful man in David's kingdom.</p>",
        "35": "<p>The double replacement — Benaiah for Joab (military), Zadok for Abiathar (priestly) — completes the institutional restructuring that began with Solomon's succession. The Zadokite priestly line's installation as the sole Jerusalem priestly dynasty has profound consequences for the rest of the biblical narrative: the Zadokites will serve the Jerusalem temple throughout the monarchy, into the exile, and are the priests whose descendants Ezekiel envisions serving the eschatological temple (Ezek 44:15). The Zadokite lineage becomes the standard of priestly legitimacy in Second Temple Judaism, connecting 1 Kings 2 to the Qumran community's claims to legitimate priesthood.</p>",
        "36": "<p>Solomon's arrangement for Shimei — build a house in Jerusalem, live there, and do not cross the Kidron Valley — is a sophisticated legal solution. Jerusalem as the assigned residence keeps Shimei under the king's surveillance without requiring explicit incarceration. The Kidron Valley (crossing it toward Bethlehem/Jericho/Jordan) represents the geographic boundary of Jerusalem — going beyond it means leaving the city where Shimei is under covenant terms. The boundary condition ('on the day you cross the Kidron, know that you shall die') is explicit and unambiguous: Shimei accepts the terms, establishing a new covenant with Solomon whose violation will provide fresh legal grounds for execution.</p>",
        "37": "<p>The death-threat formula 'know certainly that you shall die' (<em>yāḏōaʿ tēḏaʿ kî môṯ tāmûṯ</em>) is the emphatic death-sentence formula of Gen 2:17 ('you shall surely die') — the same pattern of doubled infinitive used for the tree of knowledge's prohibition. The parallel to Eden is notable: Shimei is given a bounded space (Jerusalem) and a forbidden boundary (the Kidron) with an explicit consequence for violation. Like Adam and Eve, he will cross the forbidden boundary — not because he is deceived but because his material interests (recovering his slaves) override his covenant obligation.</p>",
        "38": "<p>Shimei's acceptance of the covenant terms — 'Good is the word; as my lord the king has said, your servant will do' — constitutes a formal covenant ratification. The phrase <em>ṭôḇ haddāḇār</em> (the word is good) is covenant-acceptance language. Shimei 'lived in Jerusalem many days' (<em>yamîm rabbîm</em>) — the time-phrase indicates a period of apparent compliance before the crisis of the runaway slaves. The narrated compliance-then-violation follows a common pattern in the Deuteronomistic History: covenant acceptance followed by covenant violation when self-interest demands it.</p>",
        "39": "<p>The three-year gap before Shimei's covenant-violation establishes that the arrangement worked, until the slaves' flight created a situation where Shimei's economic interest (recovering property) conflicted with his covenant obligation (not leaving Jerusalem). The slaves fled to Gath — Philistine territory, across the Judean-Philistine border — which means retrieving them requires crossing not just the Kidron Valley but the much more significant geographic and political boundary into Philistine territory. Shimei chose his slaves over his covenant, demonstrating that his submission to Solomon's covenant terms was conditional on his own convenience rather than principled obligation.</p>",
        "40": "<p>The saddling of the donkey as preparation for the journey to Gath is the detail of ordinary life interrupting the extraordinary covenant. The ANE donkey journey — the standard mode of travel — places Shimei's violation in the most mundane context: he is not planning a coup or fleeing persecution but recovering runaway property. The ordinariness of the situation makes the covenant violation more striking: Shimei does not cross the Kidron in a moment of political crisis but on a routine property-recovery trip. The covenant's boundary applies to ordinary life, not just extraordinary circumstances — which is exactly the point of covenant law in the Deuteronomic tradition.</p>",
        "41": "<p>Solomon's intelligence system — the immediate report that Shimei had 'gone from Jerusalem to Gath and returned' — reflects the reality of royal surveillance in the ancient world. The king's administration maintained networks of informants and local officials who reported significant events to the center. Shimei's movements were apparently monitored, whether through formal surveillance or informal reporting by neighbors and officials. The detail that Solomon knew about both the departure and the return suggests the report was systematic rather than accidental — Shimei was under actual surveillance, consistent with the covenant arrangement that kept him in Jerusalem under royal oversight.</p>",
        "42": "<p>Solomon's summoning of Shimei and his recitation of the covenant terms — 'did I not make you swear by YHWH, and warn you, and say to you, Know certainly that on the day you go out to any place whatever, you will die?' — is the formal legal confrontation that establishes the violation before the execution. This procedure mirrors the covenant lawsuit (<em>rîb</em>) pattern of the prophetic tradition: YHWH brings covenant charges against Israel by reciting the covenant terms and demonstrating their violation. Solomon is conducting a covenant lawsuit against Shimei: here are the terms, here is the violation, here is the sentence.</p>",
        "43": "<p>The question 'why have you not kept the oath of YHWH and the commandment I laid on you?' elevates the covenant terms from political arrangement to religious obligation. The phrase 'oath of YHWH' (<em>šĕḇûʿaṯ YHWH</em>) means an oath sworn with YHWH as guarantor — which is what the original arrangement was (v36: 'I will make you swear by YHWH'). Breaking such an oath is not merely contract violation but sacrilege — a covenant offense against YHWH himself. Solomon's formulation makes the execution theologically justified: Shimei has not merely violated a royal decree but has broken an oath sworn to YHWH.</p>",
        "44": "<p>Solomon's final word before the execution — 'you know all the evil that your heart knows that you did to David my father' — invokes the internal conscience rather than merely the external record. The phrase <em>yāḏaʿ lĕḇāḇĕkā</em> (your heart knows) reflects the ANE and Israelite understanding that internal knowledge of guilt is a form of self-condemnation — the guilty party's own conscience witnesses against them. The blood-guilt of cursing YHWH's anointed (2 Sam 16:5-8) is now returned to Shimei's head by YHWH's justice administered through Solomon. The execution is presented as covenant justice, not personal revenge.</p>",
        "45": "<p>The theological climax of ch 2 — 'King Solomon shall be blessed, and the throne of David shall be established before YHWH forever' — is the Deuteronomistic narrator's statement of the chapter's ultimate meaning. The individual executions and political consolidations are the negative clearing-out of covenant corruption; the positive statement is the covenant blessing flowing to the faithful Davidic house. <em>Lip̄nê YHWH ʿaḏ-ʿôlām</em> (before YHWH forever) echoes the Davidic covenant of 2 Sam 7:16 precisely. The political consolidation narrative of ch 2 is simultaneously a covenant-fulfillment narrative: YHWH's purpose for the Davidic throne is being established through historical events.</p>",
        "46": "<p>'The kingdom was established in Solomon's hand' — the closing formula brackets the entire consolidation narrative that began in v12. The root <em>kûn</em> (established, firm) connects the beginning and end of ch 2 (vv12, 46) and reaches back to the Davidic covenant (2 Sam 7:12, 16). Between these two bookmarks lie the elimination of every faction that posed a threat to the covenant order: Adonijah (succession claim), Abiathar (priestly faction), Joab (military faction), and Shimei (blood-guilt). The narrative presents Solomon's consolidation not as power politics but as the establishment of covenant order in the kingdom. The 'hand' metaphor (<em>bĕyaḏ šĕlōmōh</em>) signals effective, not merely nominal, authority — the kingdom is now functioning as a covenant-governed entity under the right king.</p>"
    }
}


def main():
    existing = load_comm('mkt-context', '1kings')
    merge_comm(existing, KINGS1_CONTEXT_CH1_2)
    save_comm('mkt-context', '1kings', existing)

    ch1 = existing.get('1', {})
    ch2 = existing.get('2', {})
    print(f'ch 1: {len(ch1)} verse entries')
    print(f'ch 2: {len(ch2)} verse entries')

    interlinear_path = ROOT / 'data' / 'interlinear' / '1kings.json'
    if interlinear_path.exists():
        il = json.loads(interlinear_path.read_text())
        for ch_num in ['1', '2']:
            il_verses = set(il.get(ch_num, {}).keys())
            comm_verses = set(existing.get(ch_num, {}).keys())
            missing = il_verses - comm_verses
            if missing:
                print(f'  ch {ch_num} missing: {sorted(missing, key=int)}')
            else:
                print(f'  ch {ch_num}: complete ({len(comm_verses)}/{len(il_verses)} verses)')


if __name__ == '__main__':
    main()
